-- спасибо арз за сломанные 3д тексты
local pool_3dText = setmetatable({}, {__mode = "v"})
local rawget, rawset = table.rawget, table.rawset

function sampev.onCreate3DText(id, color, pos, dist, testLOS, attplayer, attveh, text)
    -- print(id, text)
    pool_3dText[id] = {
        color = color,
        pos = {
            x = pos.x, 
            y = pos.y, 
            z = pos.z
        },
        dist = dist,
        walls = testLOS,
        player_id = attplayer,
        car_id = attveh,
        text = text
    }
end

function sampev.onRemove3DTextLabel(id)
    if pool_3dText[id] then
        if pool_3dText[id].text:find("разгрузить машину") then
            log("ну и какого хуя")
        end
    end
    pool_3dText[id] = nil -- Прямое удаление по ключу
end

function Is3dTextDefined(id)
    return pool_3dText[id] ~= nil
end

function Get3dTextInfoById(id)
    local data = pool_3dText[id]
    if data then
        return data.text, data.color, 
               data.pos.x, data.pos.y, data.pos.z,
               data.dist, data.walls, 
               data.player_id, data.car_id
    end
    return nil
end

