-- https://www.blast.hk/threads/118464/post-951539
function renderFontDrawTextAlign(font, text, x, y, color, align)
    if not align or align == 1 then -- слева
        renderFontDrawText(font, text, x, y, color)
    end
    if align == 2 then -- по центру
        renderFontDrawText(font, text, x - renderGetFontDrawTextLength(font, text) / 2, y, color)
    end
    if align == 3 then -- справа
        renderFontDrawText(font, text, x - renderGetFontDrawTextLength(font, text), y, color)
    end
end

-- спиздил отсюда https://www.blast.hk/threads/197246/
function drawCircleIn3d(x, y, z, radius, polygons, width, color, rotation)
    rotation = rotation or 0  -- Default to no rotation
    local step = math.floor(360 / (polygons or 36))
    local sX_old, sY_old
    
    for angle = 0, 360, step do
        -- Apply rotation to the current angle
        local rotatedAngle = angle + rotation
        
        -- Calculate 3D coordinates of the point on the circle
        local lX = radius * math.cos(math.rad(rotatedAngle)) + x
        local lY = radius * math.sin(math.rad(rotatedAngle)) + y
        local lZ = z
        
        -- Convert to screen coordinates
        local _, sX, sY, sZ = convert3DCoordsToScreenEx(lX, lY, lZ)
        
        -- Draw lines if the point is visible (in front of the camera)
        if sZ > 1 then
            if sX_old and sY_old then
                renderDrawLine(sX, sY, sX_old, sY_old, width, color)
            end
            sX_old, sY_old = sX, sY
        else
            sX_old, sY_old = nil, nil  -- Reset if point is behind camera
        end
    end
end

function calcDist(x, y, z)
    local cx,cy,cz = getCharCoordinates(PLAYER_PED)
    return getDistanceBetweenCoords3d(cx,cy,cz, x,y,z)
end

