function loadBizList()
    local _bizlist = json.decode(defjson)

    -- Проверяем оба возможных пути
    local paths = {
        "moonloader/bizlist.json",
        "moonloader/finkovoz/bizlist.json"
    }
    
    local loaded = false
    for _, path in ipairs(paths) do
        if doesFileExist(path) then
            local status, err = pcall(function ()
                local file = io.open(path, "r")
                local contents = file:read("*a")
                _bizlist = json.decode(contents)
                file:close()
            end)
            if not err then
                log("Загружен внешний файл: " .. path)
                loaded = true
                break
            end
        end
    end
    
    if not loaded then
        log("{ff0000}Файл с бизнесами не обнаружен, использую встроенный список.")
        log("Создаю папку и файл для будущего использования...")
        
        -- Создаем папку finkovoz если её нет
        createDirectory("moonloader/finkovoz")
        
        -- Сохраняем встроенный список в файл
        local file = io.open("moonloader/finkovoz/bizlist.json", "w")
        if file then
            file:write(defjson)
            file:close()
            log("Создан файл: moonloader/finkovoz/bizlist.json")
        end
    end

    for _, biz in pairs(_bizlist) do
        local new_biz = bizTemplate()
        new_biz.id = biz.id
        new_biz.name = biz.name
        new_biz.location = biz.location
        new_biz.coordinates = biz.coordinates
        table.insert(bizlist, new_biz)
    end
    log("Загружено {ff0000}" .. #bizlist .. " {ffffff}бизнесов")
end



