function getClosestBiz()
    local biz_id = 0
    local biz_dist = 99999
    for idx, _ in pairs(bizlist) do
        if not isBlacklisted(bizlist[idx].id) and not bizlist[idx].hidden and bizlist[idx].owned and bizlist[idx].distance < re_distance[0] then
            if bizlist[idx].distance < biz_dist and bizlist[idx].distance > 100 then
                biz_id = bizlist[idx].id
                biz_dist = bizlist[idx].distance
            end
        end
    end
    return biz_id
end

