function isBlacklisted(id)
    local id = tonumber(id)
    local blist = {}
    for token in string.gmatch(ffi.string(filt_blacklist), "([^%.]+)") do
        table.insert(blist, token)
    end
    for _, token in pairs(blist) do
        if tonumber(token) == id then
            return true
        end
    end
    return false
end

