-- CEF-функции (взяты из Arizona-Dialog-Reborn)
local evalcef = function(code, encoded)
    encoded = encoded or 0
    local bs = raknetNewBitStream()
    raknetBitStreamWriteInt8(bs, 17)
    raknetBitStreamWriteInt32(bs, 0)
    raknetBitStreamWriteInt16(bs, #code)
    raknetBitStreamWriteInt8(bs, encoded)
    raknetBitStreamWriteString(bs, code)
    raknetEmulPacketReceiveBitStream(220, bs)
    raknetDeleteBitStream(bs)
end

local function execJS(code)
    evalcef(("(() => {%s})()"):format(code))
end

-- Хранилище данных из CEF
local _cefBuffer = nil
local _pendingDialogId = nil

-- Функция для приема данных из JS
function _G.GetCEFData(jsonStr)
    local ok, data = pcall(json.decode, jsonStr)
    if ok then
        _cefBuffer = data
        -- Обрабатываем данные сразу при получении
        if _pendingDialogId and _cefBuffer and #_cefBuffer > 0 then
            for _, entry in ipairs(_cefBuffer) do
                for _, biz in ipairs(bizlist) do
                    if biz.id == entry.id then
                        biz.profit = tonumber(entry.profit) or 0
                        biz.owned = true
                        break
                    end
                end
            end
            log("[CEF] Обновлено бизнесов: " .. #_cefBuffer)
            sampSendDialogResponse(_pendingDialogId, 0, 0, nil)
            _pendingDialogId = nil
            _cefBuffer = nil
        end
    else
        log("Ошибка CEF парсинга: " .. tostring(data))
    end
end

function sampev.onShowDialog(id, style, title, button1, button2, text)
    -- Безопасная функция преобразования в число
    local function safe_tonumber(val)
        if not val then return 0 end
        val = tostring(val):gsub("%s+", ""):gsub("%.", ""):gsub(",", "")
        return tonumber(val) or 0
    end
    
    -- Обработка денег в финковозке
    for _id, value in pairs(text:split("\n")) do
        if value:find("грузовике тепер") then
            local total = 0
            
            -- Детальная отладка
            log(" ")
            log("{ffaa00}[DEBUG] === ФИНКОВОЗКА ===")
            log("{ffaa00}[DEBUG] Сырая строка: " .. value:gsub("\t", " | "))
            
            -- Ищем сырые теги
            local kk = value:match(":KK: (%d+)")
            local k = value:match(":K: ([%d%.]+)")
            
            if kk then
                log("[DEBUG] Найдено :KK: " .. kk .. " -> " .. (safe_tonumber(kk) * 1000000))
                total = total + safe_tonumber(kk) * 1000000
            end
            if k then
                log("[DEBUG] Найдено :K: " .. k .. " -> " .. (safe_tonumber(k:gsub("%.", "")) * 1000))
                total = total + safe_tonumber(k:gsub("%.", "")) * 1000
            end
            
            -- Если тегов нет - ищем отформатированное
            if total == 0 then
                local m_val = value:match("%$(%d+%.?%d*)M")
                local b_val = value:match("%$(%d+%.?%d*)B")
                local k_val = value:match("%$(%d+%.?%d*)K")
                local plain = value:match("%$(%d[%d%s%.]*)")
                
                if b_val then
                    log("[DEBUG] Найдено $X.XXB: " .. b_val .. " -> " .. math.floor(tonumber(b_val) * 1000000000))
                    total = math.floor(tonumber(b_val) * 1000000000)
                elseif m_val then
                    log("[DEBUG] Найдено $X.XXM: " .. m_val .. " -> " .. math.floor(tonumber(m_val) * 1000000))
                    total = math.floor(tonumber(m_val) * 1000000)
                elseif k_val then
                    log("[DEBUG] Найдено $X.XXK: " .. k_val .. " -> " .. math.floor(tonumber(k_val) * 1000))
                    total = math.floor(tonumber(k_val) * 1000)
                elseif plain then
                    log("[DEBUG] Найдено обычное $XXX: " .. plain .. " -> " .. safe_tonumber(plain))
                    total = safe_tonumber(plain)
                end
            end
            
            log("{00ff00}[DEBUG] ИТОГ: " .. total .. " ($" .. add_delimiters(total) .. ")")
            incarmoney[0] = total
        end
        
        if value:find("в общак вашей орг") then
            incarmoney[0] = 0
            if ignore_claim_msg[0] then
                return false
            end
        end
    end

    if text:find("успешно загрузили в ваш грузовик") then
        if successful_gather_type[0] == 0 then
            lua_thread.create(rescan)
        end
        if ignore_gather_dlg[0] then
            sampSendDialogResponse(id, 0, 0, nil)
            return false
        end
    end

    if hidedlg then
        local foundNext = false
        if title:find("Бизнесов под крышей") then
            
            local debug_shown = false
            
            for _id, value in pairs(text:split("\n")) do
                if _id > 1 then
                    foundNext = value:find("ледующая")

                    if foundNext then
                        sampSendDialogResponse(id, 1, _id-2, nil)
                    elseif not foundNext and not value:find("редыдущ") then
                        local entry = value:split("\t")
                        local bizId = entry[1] and entry[1]:match("%((%d+)%)")
                        
                        if bizId and entry[3] then
                            local profit = 0
                            local profitField = tostring(entry[3])
                            
                            -- Показываем отладку для первого бизнеса
                            if not debug_shown then
                                debug_shown = true
                                log(" ")
                                log("{ffaa00}[DEBUG] === ПРИМЕР БИЗНЕСА ===")
                                log("{ffaa00}[DEBUG] Вся строка: " .. value:gsub("\t", " | "))
                                log("{ffaa00}[DEBUG] Поле прибыли: '" .. profitField .. "'")
                            end
                            
                            -- Проверяем наличие :KK: или :K:
                            local has_raw_tags = profitField:find(":KK:") or profitField:find(":K:")
                            
                            if not debug_shown then
                                -- уже показали
                            end
                            
                            if has_raw_tags then
                                -- Сырые теги - умножаем
                                local kk = profitField:match(":KK: (%d+)")
                                local k = profitField:match(":K: ([%d%.]+)")
                                
                                if not debug_shown then end
                                
                                if kk then 
                                    profit = profit + safe_tonumber(kk) * 1000000
                                end
                                if k then 
                                    profit = profit + safe_tonumber(k:gsub("%.", "")) * 1000
                                end
                                
                                if _id == 2 then
                                    log("[DEBUG] Тип: СЫРЫЕ ТЕГИ")
                                    if kk then log("[DEBUG]   KK: " .. kk .. " -> " .. safe_tonumber(kk) * 1000000) end
                                    if k then log("[DEBUG]   K: " .. k .. " -> " .. safe_tonumber(k:gsub("%.", "")) * 1000) end
                                end
                            else
                                -- Отформатированные данные - парсим суффиксы
                                local m_val = profitField:match("%$(%d+%.?%d*)M")
                                local b_val = profitField:match("%$(%d+%.?%d*)B")
                                local k_val = profitField:match("%$(%d+%.?%d*)K")
                                local plain = profitField:match("%$(%d[%d%s%.]*)")
                                
                                if _id == 2 then
                                    log("[DEBUG] Тип: ОТФОРМАТИРОВАНО")
                                    if b_val then log("[DEBUG]   B: " .. b_val) end
                                    if m_val then log("[DEBUG]   M: " .. m_val) end
                                    if k_val then log("[DEBUG]   K: " .. k_val) end
                                    if plain then log("[DEBUG]   Plain: " .. plain) end
                                end
                                
                                if b_val then
                                    profit = math.floor(tonumber(b_val) * 1000000000)
                                elseif m_val then
                                    profit = math.floor(tonumber(m_val) * 1000000)
                                elseif k_val then
                                    profit = math.floor(tonumber(k_val) * 1000)
                                elseif plain then
                                    profit = safe_tonumber(plain)
                                else
                                    -- Просто число без $
                                    local num = profitField:match("(%d[%d%s%.]*)")
                                    if num then
                                        profit = safe_tonumber(num)
                                        if _id == 2 then
                                            log("[DEBUG]   Num (без $): " .. num)
                                        end
                                    end
                                end
                            end
                            
                            if _id == 2 then
                                log("{00ff00}[DEBUG] ИТОГ прибыли: " .. profit .. " ($" .. add_delimiters(profit) .. ")")
                            end
                            
                            if profit > 0 then
                                for idx, biz in pairs(bizlist) do
                                    if tostring(biz.id) == bizId then
                                        bizlist[idx].profit = profit
                                        bizlist[idx].owned = true
                                        break
                                    end
                                end
                            end
                        end
                    end        
                end
            end

            if not foundNext then
                sampSendDialogResponse(id, 0, 0, nil)
            end

            return false
        elseif title:find("еню сражени") then
            sampSendDialogResponse(id, 0, 0, nil)
            hidedlg = false
            return false
        end
    end
end

