    end
    log("Данные о прибыли сброшены. Если бизнесы не отобржаются откройте /mbiz для обновления.")
end)

-- Вспомогательная функция для обновления данных
function updateBizData(bizId, profit)
    bizId = tostring(bizId)
    profit = tonumber(profit)
    
    if not bizId or not profit then return end
    
    for _, biz in ipairs(bizlist) do
        if tostring(biz.id) == bizId then
            biz.profit = profit
            biz.owned = true
            return
        end
    end
end




function drawMarkers()
    if not map_enabled[0] then return end
    if (os.clock() - dm_lasttime) * 1000 >= 1000 and isSampAvailable() then
        destroyMarkers()
        for idx, _ in pairs(bizlist) do
            if not isBlacklisted(bizlist[idx].id) and not bizlist[idx].hidden and bizlist[idx].owned and bizlist[idx].distance < re_distance[0] and bizlist[idx].profit > 0 then
                createMarker(
                    bizlist[idx].coordinates.x,
                    bizlist[idx].coordinates.y,
                    bizlist[idx].coordinates.z
                )
            end
        end
        dm_lasttime = os.clock()
    end
end

function render()
    rot = rot + gm_rot_speed[0]
    if #bizlist > 0 then
        local x,y,z = getCharCoordinates(PLAYER_PED)
        local cx, cy = convert3DCoordsToScreen(x,y,z)
        for _, biz in pairs(bizlist) do
            if not biz.hidden and biz.owned and biz.profit >= filt_thres_profit[0] and biz.distance < filt_thres_dist[0] then
                local bx = biz.coordinates.x
                local by = biz.coordinates.y
                local bz = biz.coordinates.z

                local scrx, scry = convert3DCoordsToScreen(bx, by, bz)

                if biz.distance < autogather_radius[0] and autogather[0] then
                    if (os.clock() - ag_lasttime) * 1000 >= autogather_rate[0] then
                        if incarmoney[0] < 10000000 then
                            honk()
                        end
                        ag_lasttime = os.clock()
                    end
                end

                if isPointCorrect(bx, by, bz, 1) and biz.distance < re_distance[0] then
                    local offy = -50
                    if draw_tracers[0] then
                        renderDrawLine(cx, cy, scrx, scry, 1, makeHexColor({tr_alpha[0], 255,0,0}))
                    end
                    if green_marker[0] then
                        for rad=0, gm_radius[0], gm_density[0] do
                            drawCircleIn3d(bx, by, bz-0.6, rad, gm_poly[0], 1, makeHexColor({gm_alpha[0],0,255,0}), rot)
                        end
                    end

                    if biz_popup[0] then
                        renderFontDrawTextAlign(
                            fonts[font_size[0]].big,
                            "[{ff0000}".. biz.id .. "{ffffff}] " .. biz.name,
                            scrx,
                            scry+offy,
                            makeHexColor({bp_alpha[0], 255,255,255}),
                            2
                        )
                        offy = offy + renderGetFontDrawHeight(fonts[font_size[0]].big)
                        renderFontDrawTextAlign(
                            fonts[font_size[0]].small,
                            math.round(biz.distance, 1) .. "м | {00ff00}" .. formatMoney(biz.profit),
                            scrx,
                            scry+offy,
                            makeHexColor({bp_alpha[0], 255,255,255}),
                            2
                        )
                    end
                end
            end
        end
    end
end

function showGatherProgress()
    if not progbar_show[0] then return end
    local pos = {x=progbar_pos_x[0], y=progbar_pos_y[0]}
    local size = {w=progbar_size_w[0], h=progbar_size_h[0]}

    local color = makeHexColor({math.round(progbar_alpha[0] / 2, 0), 255, 255, 255})
    local prog = math.round((incarmoney[0]/10000000) * 100, 1)

    renderDrawBox(pos.x , pos.y, size.w, size.h, makeHexColor({math.round(progbar_alpha[0] / 6, 0), 0, 255, 0}))
    renderDrawBox(pos.x , pos.y, (prog / 100) * size.w, size.h, makeHexColor({progbar_alpha[0], 0, 255, 0}))

    renderDrawLine(pos.x, pos.y, pos.x+size.w, pos.y, 1, color) -- 1 hor
    renderDrawLine(pos.x, pos.y + size.h, pos.x+size.w, pos.y + size.h, 1, color) -- 2 hor

    renderDrawLine(pos.x, pos.y, pos.x, pos.y+size.h, 1, color) -- left vert
    renderDrawLine(pos.x + size.w, pos.y, pos.x + size.w, pos.y+size.h, 1, color) -- right vert

    local fh = renderGetFontDrawHeight(font)
    renderFontDrawTextAlign(font, prog .. "%", pos.x + (size.w / 2), (pos.y - (fh / 2)) + (size.h / 2), makeHexColor({progbar_alpha[0], 255, 255, 255}), 2)
    
end


