function updateBizDist()
    for _, biz in pairs(bizlist) do
        bizlist[_].distance = calcDist(biz.coordinates.x, biz.coordinates.y, biz.coordinates.z)
        bizlist[_].hidden = isBlacklisted(bizlist[_].id)
    end
end

function sortBiz()
    for i, biz in ipairs(bizlist) do
        biz.__tmp_index = i
    end

    table.sort(bizlist, function(a, b)
        if sort_variant[0] == 0 then
            if a.profit ~= b.profit then
                if sort_order[0] == 0 then
                    return a.profit > b.profit
                else
                    return a.profit < b.profit
                end
            end
            return a.__tmp_index < b.__tmp_index 
        else
            if a.distance ~= b.distance then
                if sort_order[0] == 0 then
                    return a.distance > b.distance
                else
                    return a.distance < b.distance
                end
            end
            return a.__tmp_index < b.__tmp_index 
        end

    end)

    for _, biz in ipairs(bizlist) do
        biz.__tmp_index = nil
    end
end

