local GITHUB_SCRIPT_URL = "https://github.com/eduardo-set/arz-script/blob/main/finkovoz.lua"
local GITHUB_BIZLIST_URL = "https://github.com/eduardo-set/arz-script/blob/main/bizlist.json"
local UPDATE_CHECK_INTERVAL = 3600 -- секунды (1 час)

local last_script_check = 0
local last_bizlist_check = 0
local last_script_etag = nil
local last_bizlist_etag = nil

-- Функция загрузки с GitHub
local function downloadFromGithub(url, etag)
    local headers = {}
    if etag then
        headers["If-None-Match"] = etag
    end
    
    local result, response = pcall(function()
        return sampGetHttpResponse(url, headers)
    end)
    
    if not result then
        return nil, nil, "request_failed"
    end
    
    local status = response.status
    local body = response.body
    local new_etag = response.headers and response.headers.ETag
    
    if status == 304 then
        return nil, new_etag, "not_modified"
    end
    
    if status ~= 200 then
        return nil, nil, "http_" .. status
    end
    
    return body, new_etag, nil
end

-- Получение версии из содержимого скрипта
local function extractVersion(content)
    local version = content:match('local script_ver%s*=%s*"([^"]+)"')
    return version
end

-- Проверка обновления скрипта
function checkScriptUpdate(silent)
    if not silent then
        log("Проверка обновлений скрипта...")
    end
    
    local content, etag, err = downloadFromGithub(GITHUB_SCRIPT_URL, last_script_etag)
    
    if err == "not_modified" then
        if not silent then
            log("Скрипт не изменился")
        end
        return false
    end
    
    if err then
        if not silent then
            log("Ошибка проверки скрипта: " .. err)
        end
        return false
    end
    
    -- Извлекаем версию из GitHub
    local remote_version = extractVersion(content)
    if not remote_version then
        if not silent then
            log("Не удалось определить версию скрипта")
        end
        return false
    end
    
    -- Сравниваем версии
    local current_version = script_ver:gsub("%[PUBLIC%]", ""):gsub("%s+", "")
    remote_version = remote_version:gsub("%[PUBLIC%]", ""):gsub("%s+", "")
    
    if current_version == remote_version then
        if not silent then
            log("У вас актуальная версия: " .. current_version)
        end
        last_script_etag = etag
        return false
    end
    
    if not silent then
        log(string.format("Найдена новая версия: %s (у вас %s)", remote_version, current_version))
        log("Скачиваю обновление...")
    end
    
    -- Сохраняем бэкап текущего скрипта
    local current_file = io.open(thisScript().path, "r")
    if current_file then
        local backup_content = current_file:read("*a")
        current_file:close()
        
        local backup_path = thisScript().path .. ".backup"
        local backup = io.open(backup_path, "w")
        if backup then
            backup:write(backup_content)
            backup:close()
            log("Бэкап сохранен: " .. backup_path)
        end
    end
    
    -- Сохраняем новую версию
    local file = io.open(thisScript().path, "w")
    if not file then
        if not silent then
            log("Ошибка сохранения скрипта")
        end
        return false
    end
    
    file:write(content)
    file:close()
    
    last_script_etag = etag
    
    if not silent then
        log("{00ff00}Скрипт обновлен до версии " .. remote_version)
        log("{ffaa00}Перезагрузите скрипт: /ml reload " .. script_name())
    end
    
    return true
end

-- Проверка обновления bizlist.json
function checkBizlistUpdate(silent)
    if not silent then
        log("Проверка обновлений bizlist.json...")
    end
    
    local content, etag, err = downloadFromGithub(GITHUB_BIZLIST_URL, last_bizlist_etag)
    
    if err == "not_modified" then
        if not silent then
            log("Bizlist не изменился")
        end
        return false
    end
    
    if err then
        if not silent then
            log("Ошибка загрузки bizlist: " .. err)
        end
        return false
    end
    
    -- Проверяем валидность JSON
    local ok, data = pcall(json.decode, content)
    if not ok then
        if not silent then
            log("Ошибка: невалидный JSON в bizlist")
        end
        return false
    end
    
    -- Создаем папку
    createDirectory("moonloader/finkovoz")
    
    -- Сохраняем файл
    local file = io.open("moonloader/finkovoz/bizlist.json", "w")
    if not file then
        if not silent then
            log("Ошибка сохранения bizlist.json")
        end
        return false
    end
    
    file:write(content)
    file:close()
    
    last_bizlist_etag = etag
    
    -- Перезагружаем список бизнесов
    local old_count = #bizlist
    bizlist = {}
    loadBizList()
    
    if not silent then
        log(string.format("Bizlist обновлен! Бизнесов: %d (было %d)", #bizlist, old_count))
    end
    
    destroyMarkers()
    return true
end

-- Периодическая проверка всех обновлений
function autoUpdateLoop()
    while true do
        wait(UPDATE_CHECK_INTERVAL * 1000)
        if isSampAvailable() and script_enabled then
            checkScriptUpdate(true)
            checkBizlistUpdate(true)
        end
    end
end

-- Команды
sampRegisterChatCommand("update", function()
    checkScriptUpdate(false)
end)

sampRegisterChatCommand("updatebiz", function()
    checkBizlistUpdate(false)
end)

sampRegisterChatCommand("updateall", function()
    checkScriptUpdate(false)
    checkBizlistUpdate(false)
end)

sampRegisterChatCommand("seturl", function(url)
    if url and url:len() > 10 and url:find("https://") then
        GITHUB_SCRIPT_URL = url
        last_script_etag = nil
        log("URL скрипта обновлен!")
    else
        log("Использование: /seturl [RAW_URL]")
    end
end)

sampRegisterChatCommand("setbizurl", function(url)
    if url and url:len() > 10 and url:find("https://") then
        GITHUB_BIZLIST_URL = url
        last_bizlist_etag = nil
        log("URL bizlist обновлен!")
    else
        log("Использование: /setbizurl [RAW_URL]")
    end
end)

sampRegisterChatCommand("version", function()
    log("Текущая версия: " .. script_ver)
    log("Проверка обновлений: /update")
end)

-- Запускаем поток автообновления
lua_thread.create(autoUpdateLoop)

-- Отложенный вывод сообщений
lua_thread.create(function()
    wait(3000)
    if isSampAvailable() then
        log("{00ff00}Автообновление активировано")
        log("Команды: /update, /updatebiz, /updateall, /version")
    end
end)

function onScriptTerminate(scr, quit)
    if thisScript() == scr then
        destroyMarkers()
    end
end
